  /** Higher value means higher priority when overriding */
  private getDayTypePriority(dayType?: string | null, seasonType?: string | null) {
    const normalizedDayType = [DayType.WEEKDAY, DayType.WEEKEND].includes(dayType as DayType)
      ? (dayType as DayType)
      : null;
    const normalizedType =
      seasonType ?? (dayType === SeasonType.EVENT ? SeasonType.EVENT : SeasonType.SEASON);

    if (!normalizedDayType && !normalizedType) {
